"""PropelPay v3.0"""
import logging, os, asyncio
from contextlib import asynccontextmanager
from fastapi import FastAPI
from fastapi.middleware.cors import CORSMiddleware
from fastapi.responses import HTMLResponse
from app.database import init_db
from app.api import auth, clients, proposals, invoices, dashboard, billing
from app.api.banks import router as banks_router
from app.api.recurring import router as recurring_router, process_due_recurring
from app.api.payments_api import router as payments_router

logging.basicConfig(level=logging.INFO, format="%(asctime)s %(levelname)s %(name)s: %(message)s")
logger = logging.getLogger(__name__)

async def recurring_scheduler():
    while True:
        try:
            await asyncio.sleep(3600)
            fired = await process_due_recurring()
            if fired: logger.info(f"Recurring: fired {fired} invoice(s)")
        except Exception as e: logger.error(f"Scheduler: {e}")

@asynccontextmanager
async def lifespan(app: FastAPI):
    logger.info("PropelPay v3.0 starting...")
    await init_db()
    os.makedirs("uploads", exist_ok=True)
    asyncio.create_task(recurring_scheduler())
    yield

app = FastAPI(title="PropelPay API", version="3.0.0", docs_url="/docs", redoc_url="/redoc", lifespan=lifespan)
app.add_middleware(CORSMiddleware, allow_origins=["*"], allow_credentials=True, allow_methods=["*"], allow_headers=["*"])

app.include_router(auth.router)
app.include_router(clients.router)
app.include_router(proposals.router)
app.include_router(invoices.router)
app.include_router(dashboard.router)
app.include_router(billing.router)
app.include_router(banks_router)
app.include_router(recurring_router)
app.include_router(payments_router)

